package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsQuoting_whenQuoteCharIsNotNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.isQuoting());
    }

    @Test
    void testIsQuoting_whenQuoteCharIsNull() throws Exception {
        // Create a CSVFormat instance with quoteChar set to null via withQuoteChar method
        CSVFormat format = CSVFormat.DEFAULT.withQuoteChar((Character) null);
        assertFalse(format.isQuoting());
    }
}
